INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '93cf3bea-0f07-41ef-91cb-86bfa1b6661f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular Component Design — Single Responsibility, the 150-Line Rule, and Splitting Smart from Dumb$escape$,
  $escape$Angular components balloon fast when you mix data-fetching, state management, and template logic in one class. The 150-line rule is a forcing function: if your component file exceeds it, extract. The pattern that pays most dividends is the container/presentational split — a 'smart' component owns the `@ngrxStore` selects, `HttpClient` calls, and event handlers, while a 'dumb' component receives `@Input()` data and emits `@Output()` events, nothing more. Dumb components are pure by nature: given the same inputs, they render identically. This makes them trivially testable with `ComponentFixture` and `NO_ERRORS_SCHEMA`, and freely reusable across routes. Apply `ChangeDetectionStrategy.OnPush` to every presentational component — Angular will skip change detection unless an `@Input()` reference changes, a bound `async` pipe emits, or you manually call `markForCheck()`. For logic that doesn't belong in either layer — mapping API DTOs to view models, sorting, filtering — push it into a pure `@Injectable({ providedIn: 'root' })` service or a standalone pipe. Components should orchestrate, not compute.$escape$,
  $escape$// smart.component.ts — owns data
@Component({
  selector: 'app-feed',
  template: `<app-feed-list [items]="items$ | async" (selected)="onSelect($event)" />`
})
export class FeedComponent {
  items$ = this.store.select(selectFeedItems);
  constructor(private store: Store) {}
  onSelect(id: string) { this.store.dispatch(FeedActions.select({ id })); }
}

// dumb.component.ts — owns display
@Component({
  selector: 'app-feed-list',
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<li *ngFor="let item of items" (click)="selected.emit(item.id)">{{ item.title }}</li>`
})
export class FeedListComponent {
  @Input() items: FeedItem[] | null = [];
  @Output() selected = new EventEmitter<string>();
}$escape$,
