INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9c9906d8-2a97-425f-ac7f-f1c1f107e273',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular computed() and memo strategies — When They Help vs. Hurt$escape$,
  $escape$Angular's signals API (v17+) brings `computed()` as the primary memoization primitive. Unlike React's `useMemo`, `computed()` is fully reactive — it re-evaluates only when its signal dependencies change, tracked automatically at runtime. Use it for expensive derivations: filtered lists, aggregated totals, transformed data. Avoid it for trivial reads like `signal() + 1` — the tracking overhead exceeds the benefit.

For template expressions, Angular's change detection already skips re-evaluation in OnPush components when inputs haven't changed. Wrapping a cheap getter in `computed()` inside an OnPush component is redundant — the component won't re-render anyway.

The real win is cross-component sharing: a `computed()` defined in a service runs once per signal change regardless of how many components inject it. Contrast this with a plain getter in a service, which re-executes on every read.

Avoid chaining many `computed()` calls deeply — Angular evaluates the dependency graph lazily, but excessive nesting increases graph traversal cost. Flatten where possible.$escape$,
  $escape$import { signal, computed, Injectable } from '@angular/core';

@Injectable({ providedIn: 'root' })
export class ProductStore {
  private products = signal<Product[]>([]);
  private filter = signal<string>('');

  // Memoized: only re-runs when products or filter changes
  readonly filtered = computed(() =>
    this.products().filter(p =>
      p.name.toLowerCase().includes(this.filter().toLowerCase())
    )
  );

  // Anti-pattern: computed() wrapping a trivial read
  // readonly count = computed(() => this.products().length); // just use products().length in template
}$escape$,
  $escape$typescript$escape$,
