INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd748a50c-de8f-48ef-923c-aa3702969c16',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular Component Inputs — Discriminated Unions Over Loose Props$escape$,
  $escape$Angular 17.1+ input() signals make prop typing even more critical. Avoid `any` or bloated optional-everything interfaces by modeling variants as discriminated unions on your `@Input()` or `input()` declarations.

Consider a `<app-badge>` that renders differently for 'status', 'count', and 'label' modes. A single interface with every field optional forces defensive checks everywhere. Instead, define a union type where each member has a literal `type` discriminant — TypeScript's control-flow narrowing then makes the wrong fields invisible in each branch.

Inside the component, inject the `BadgeProps` via `input.required<BadgeProps>()`. In the template, Angular's `@switch` on `props().type` narrows correctly: in the `'count'` branch, `props().value` is typed as `number`, not `number | string | undefined`.

This pattern eliminates runtime guards like `if (props.value !== undefined)`, catches misuse at the call site (`<app-badge [props]="{ type: 'count', label: 'x' }" />` won't compile), and makes the component's API self-documenting without a single JSDoc comment.$escape$,
  $escape$// badge.types.ts
type StatusBadge = { type: 'status'; state: 'online' | 'offline' };
type CountBadge  = { type: 'count';  value: number };
type LabelBadge  = { type: 'label';  text: string; color?: string };
export type BadgeProps = StatusBadge | CountBadge | LabelBadge;

// badge.component.ts
import { Component, input } from '@angular/core';
import { BadgeProps } from './badge.types';

@Component({
  selector: 'app-badge',
  template: `
    @switch (props().type) {
      @case ('status') { <span [class]="props().state"></span> }
      @case ('count')  { <span>{{ props().value }}</span> }
      @case ('label')  { <span [style.color]="props().color">{{ props().text }}</span> }
    }
  `
})
export class BadgeComponent {
  props = input.required<BadgeProps>();
}$escape$,
  $escape$typescript$escape$,
