INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '18a77e83-1c0b-4241-92c1-e5026c4564f1',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular Testing Library — Test What Users See, Not What Components Do$escape$,
  $escape$Angular Testing Library (@testing-library/angular) flips the default TestBed mindset: instead of querying by component class or CSS selector, you query by what a real user perceives — visible text, ARIA roles, labels, and placeholders. This forces tests to survive refactors that don't change behaviour.

With vanilla TestBed you might do `fixture.debugElement.query(By.css('.submit-btn'))`. That breaks the moment you rename a class. With Testing Library, `screen.getByRole('button', { name: /submit/i })` survives any styling change because it mirrors how assistive technology navigates your UI.

The philosophy also discourages testing internal state. Don't assert on `component.isLoading`; assert on `screen.getByRole('status')` or `screen.queryByText('Loading...')`. Fire events with `userEvent.click()` rather than calling component methods directly — it dispatches the full browser event chain, including `focusin` and `blur`, catching bugs that `triggerEventHandler('click')` silently misses.

Result: tests that document real user journeys, fail only on real regressions, and double as living accessibility audits.$escape$,
  $escape$import { render, screen } from '@testing-library/angular';
import userEvent from '@testing-library/user-event';
import { SearchComponent } from './search.component';

it('displays results after searching', async () => {
  await render(SearchComponent);

  await userEvent.type(
    screen.getByRole('searchbox', { name: /search/i }),
    'NgRx'
  );
  await userEvent.click(screen.getByRole('button', { name: /search/i }));

  expect(await screen.findByRole('list', { name: /results/i })).toBeInTheDocument();
  expect(screen.queryByText('No results found')).not.toBeInTheDocument();
});$escape$,
