INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ac37f0aa-0b1a-4516-8ad6-d43f2f85df0f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular i18n — Stop Hardcoding Strings, Use $localize and Built-in Pipes$escape$,
  $escape$Angular's built-in `$localize` tagged template literal is the idiomatic way to mark strings for extraction — never inline raw text in templates or TypeScript. Running `ng extract-i18n` generates an XLIFF/XMB file translators consume. At build time, Angular compiles locale-specific bundles, eliminating runtime lookup overhead entirely.

For dates, numbers, currencies, and percentages, Angular's pipes (`DatePipe`, `CurrencyPipe`, `DecimalPipe`, `PercentPipe`) delegate to the Intl API internally. Register the locale data you need with `registerLocaleData`, provide `LOCALE_ID` at the application level, and the pipes pick it up automatically — no manual `Intl.DateTimeFormat` calls needed.

For runtime locale-switching without rebuilding (common in SPAs), use `ngx-translate`: inject `TranslateService`, call `use('de')` on preference change, and bind with `{{ 'KEY' | translate }}`. Keep keys namespaced (`dashboard.header.title`) rather than using raw sentences — copy changes break sentence-as-key schemes. Never co-locate translated strings directly in component TypeScript; all user-facing text belongs in your XLIFF file or translation JSON, making audits and handoffs reliable.$escape$,
  $escape$// app.config.ts — register locale once at bootstrap
import { registerLocaleData } from '@angular/common';
import localeDe from '@angular/common/locales/de';
import { LOCALE_ID, ApplicationConfig } from '@angular/core';

registerLocaleData(localeDe);

export const appConfig: ApplicationConfig = {
  providers: [{ provide: LOCALE_ID, useValue: 'de-DE' }]
};

// product.component.ts
import { Component } from '@angular/core';
import { DatePipe, CurrencyPipe } from '@angular/common';

@Component({
  standalone: true,
  imports: [DatePipe, CurrencyPipe],
  template: `
    <h2>{{ heading }}</h2>
    <span>{{ releaseDate | date:'longDate' }}</span>
    <span>{{ price | currency }}</span>
  `
})
export class ProductComponent {
  heading = $localize`:@@product.heading:Latest Releases`;
  releaseDate = new Date();
  price = 49.99;
}$escape$,
  $escape$typescript$escape$,
