INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '124f051d-a915-448f-bc9d-83945b935a87',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular Memory Leaks — ngOnDestroy, AbortController, and takeUntilDestroyed$escape$,
  $escape$Angular components that subscribe to Observables, attach DOM listeners, or fire HTTP requests without cleanup are memory leak factories. Every active subscription holds a reference to the component, preventing garbage collection long after the view is destroyed.

The classic fix is implementing OnDestroy and calling unsubscribe() inside a Subject-based pattern — but Angular 16+ ships takeUntilDestroyed(), a DestroyRef-backed operator that handles this automatically, even inside inject() calls outside the component class.

For native DOM listeners added via addEventListener, you must call removeEventListener in ngOnDestroy with the exact same function reference — anonymous functions won't match. Store the handler as a class property.

For in-flight HTTP requests, Angular's HttpClient doesn't auto-cancel on destroy. Pair takeUntilDestroyed() with your HTTP stream, or manually wire an AbortController signal via HttpClient's context/fetch API if you need native cancellation semantics.

Avoid manual unsubscribe() arrays — they're error-prone. Prefer the reactive pattern: one Subject + takeUntil, or the modern inject(DestroyRef) + takeUntilDestroyed() combo.$escape$,
  $escape$import { Component, OnInit, inject } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { HttpClient } from '@angular/common/http';

@Component({ selector: 'app-feed', template: '' })
export class FeedComponent implements OnInit {
  private http = inject(HttpClient);
  private destroyRef = inject(DestroyRef); // auto from DI
  private clickHandler = () => console.log('clicked');

  ngOnInit() {
    // Subscription auto-cancelled when component destroys
    this.http.get('/api/feed')
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(data => console.log(data));

    window.addEventListener('click', this.clickHandler);
  }

  ngOnDestroy() {
    window.removeEventListener('click', this.clickHandler);
  }
}$escape$,
  $escape$typescript$escape$,
