INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cb704d0b-6b6e-474f-866e-26819e2e33ff',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular Environment Config — Validate with Zod at Bootstrap, Never at Runtime$escape$,
  $escape$Angular's built-in `environment.ts` / `environment.prod.ts` files — swapped via `fileReplacements` in `angular.json` — give you build-time config but carry zero validation. A mistyped key or missing `apiUrl` silently becomes `undefined`, surfacing only when an HTTP call fails in production.

Pair them with Zod: define a schema, call `EnvSchema.parse(environment)` at module initialisation, and bind the validated result to an `InjectionToken<AppEnv>`. Because `parse()` throws synchronously on failure, the error surfaces at bootstrap — not in a 3 AM incident.

Provide `APP_ENV` with `useValue` (not `useFactory`) so validation executes before any service constructor fires. In services and standalone components, inject with `inject(APP_ENV)` for a fully typed object — no more `environment.apiUrl!` non-null assertions or defensive `?.` chains. Swap the token in unit tests via `{ provide: APP_ENV, useValue: mockEnv }` without touching real config.

For Angular SSR, add a second Zod schema over `process.env` in `server.ts` for the same startup guarantee on the Node side.$escape$,
  $escape$// env.token.ts
import { InjectionToken } from '@angular/core';
import { z } from 'zod';

const EnvSchema = z.object({
  apiUrl: z.string().url(),
  authDomain: z.string().min(1),
  production: z.boolean(),
});

export type AppEnv = z.infer<typeof EnvSchema>;
export const APP_ENV = new InjectionToken<AppEnv>('APP_ENV');

// app.config.ts — throws at bootstrap before any service fires
import { environment } from './environments/environment';
export const envProvider = { provide: APP_ENV, useValue: EnvSchema.parse(environment) };$escape$,
  $escape$typescript$escape$,
