INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '94385005-b794-4eb3-bc8d-b10a117e9b31',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular Animations — CSS for Simple States, @angular/animations for Complex, prefers-reduced-motion Always$escape$,
  $escape$Reach for plain CSS transitions first. Toggling a class with a host binding or [class.active] covers 80% of UI state changes — hover, focus, open/closed — without touching Angular's animation engine at all.

For sequenced, staggered, or state-machine animations, use @angular/animations. Wrap the app with BrowserAnimationsModule (or provideAnimationsAsync() in standalone), then define triggers with trigger(), state(), style(), and transition() directly on the component. Angular wires the DOM updates to animation lifecycle so you never fight change detection.

The part most teams skip: respecting prefers-reduced-motion. Inject the BreakpointObserver from @angular/cdk/layout and observe '(prefers-reduced-motion: reduce)'. When true, swap your AnimationMetadata array for a zero-duration NoopAnimationsModule alias or simply pass [] to the trigger — no CSS overrides needed. Wire this at bootstrap with provideAnimations() vs provideNoopAnimations() based on the user's OS setting so the entire app honors the preference without component-level guards.$escape$,
  $escape$// app.config.ts — honor prefers-reduced-motion at bootstrap
import { provideAnimations, provideNoopAnimations } from '@angular/platform-browser/animations';

const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

export const appConfig: ApplicationConfig = {
  providers: [
    prefersReduced ? provideNoopAnimations() : provideAnimations(),
  ],
};

// component — Angular animation trigger for panel expand
@Component({
  animations: [
    trigger('expand', [
      state('collapsed', style({ height: '0', opacity: 0, overflow: 'hidden' })),
      state('expanded',  style({ height: '*', opacity: 1 })),
      transition('collapsed <=> expanded', animate('200ms ease-in-out')),
    ]),
  ],
  template: `<div [@expand]="isOpen ? 'expanded' : 'collapsed'">...</div>`,
})
export class PanelComponent { isOpen = false; }$escape$,
  $escape$typescript$escape$,
