INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2c4b844b-b318-4ea3-b854-21ecaa4f363a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular Bundle Optimization — Tree-Shaking, Lazy Routes, and Bundle Analysis$escape$,
  $escape$Angular's build pipeline (esbuild via `@angular/build`) performs tree-shaking automatically, but you can sabotage it by importing entire modules. Import only what you need: `import { MatButtonModule } from '@angular/material/button'` instead of all of `MatModule`. For heavy components — rich text editors, chart libraries, PDF viewers — use route-level lazy loading via `loadComponent()` in your route config. This defers the chunk until navigation, keeping the initial bundle lean. For library-heavy features, combine lazy routes with `loadChildren()` pointing to a standalone routes array. To audit what's bloating your bundle, run `ng build --stats-json` and feed `dist/stats.json` into `webpack-bundle-analyzer` (still works with esbuild output via `esbuild-bundle-analyzer`). Look for duplicate dependencies, unexpectedly large chunks, and eagerly loaded modules that should be lazy. Set `budgets` in `angular.json` to enforce size limits in CI — builds fail if a bundle exceeds your threshold, preventing regressions from sneaking in.$escape$,
  $escape$// app.routes.ts — lazy-load a heavy standalone component
export const routes: Routes = [
  {
    path: 'editor',
    loadComponent: () =>
      import('./editor/editor.component').then(m => m.EditorComponent),
  },
  {
    path: 'dashboard',
    loadChildren: () =>
      import('./dashboard/dashboard.routes').then(m => m.DASHBOARD_ROUTES),
  },
];

// angular.json — enforce bundle budgets
// "budgets": [
//   { "type": "initial", "maximumWarning": "500kb", "maximumError": "1mb" },
//   { "type": "anyComponentStyle", "maximumWarning": "4kb" }
// ]$escape$,
