INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3e818a83-36ce-4a36-a0a6-ca19222f36aa',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular Production Monitoring — Sentry, Web Vitals, and Source Maps$escape$,
  $escape$Angular's build pipeline makes production debugging surprisingly clean when wired correctly. Install `@sentry/angular` and initialize it in `main.ts` before `bootstrapApplication`, passing `dsn`, `environment`, and `release` (match your CI build hash). Register `SentryErrorHandler` as Angular's `ErrorHandler` provider and add `TraceService` to catch route-level performance traces via the Angular Router integration.

For Web Vitals, use the `web-vitals` package inside `APP_INITIALIZER` — report `onCLS`, `onLCP`, `onINP`, and `onFID` to Sentry via `Sentry.captureEvent` with a `measurement` type, or pipe them to your analytics endpoint. This hooks into Angular's app lifecycle cleanly.

Source maps are the critical piece. In `angular.json`, set `sourceMap: { scripts: true, hidden: true }` under the production configuration — `hidden` prevents browsers from loading maps publicly while still letting Sentry symbolicate. Upload maps during CI using `sentry-cli releases files <release> upload-sourcemaps ./dist/<app-name>/browser` after `ng build --configuration production`.$escape$,
  $escape$// main.ts
import * as Sentry from '@sentry/angular';
import { bootstrapApplication } from '@angular/platform-browser';
import { AppComponent } from './app/app.component';
import { appConfig } from './app/app.config';

Sentry.init({
  dsn: 'https://<key>@sentry.io/<project>',
  release: import.meta.env['NG_APP_RELEASE'],
  environment: import.meta.env['NG_APP_ENV'],
  integrations: [Sentry.browserTracingIntegration()],
  tracesSampleRate: 0.2,
});

bootstrapApplication(AppComponent, appConfig);$escape$,
  $escape$typescript$escape$,
