INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f625484a-0477-4d56-a1d4-6434b50e79d1',
  '00000000-0000-0000-0000-000000000001',
  $escape$Angular's Reactivity vs React, Vue, Svelte & Solid — What Zone.js and Signals Actually Do$escape$,
  $escape$Angular's default change detection runs a full dirty-check of the component tree after every async event — clicks, HTTP responses, timers — because zone.js monkey-patches these APIs. This is closest to React's virtual DOM model: both re-evaluate broadly, then reconcile differences.

Vue's Proxy-based reactivity and Svelte's compile-time subscriptions are more surgical — only components that consumed a reactive value re-run. Angular Signals (stable since v17) bring the same fine-grained model, mirroring Solid's push-based approach. A signal() update propagates only to computed() and effect() that directly read it — not the whole tree.

Switch to ChangeDetectionStrategy.OnPush plus Signals and you escape zone.js entirely: no more unnecessary CD cycles in parent components, no markForCheck() boilerplate. The Angular team is progressively making Signals the default primitives — EXPERIMENTAL_provideZonelessChangeDetection lets you opt out of zone.js today for fully reactive, pull-free applications. Every other framework already lives here; Angular now gives you the on-ramp.$escape$,
  $escape$// Zone-based (default): CD runs on ANY async event in the tree
@Component({ changeDetection: ChangeDetectionStrategy.Default })
export class ZoneComponent {
  count = 0;
  increment() { this.count++; } // zone.js triggers full CD pass
}

// Signal-based (v17+): only direct consumers re-evaluate
@Component({ changeDetection: ChangeDetectionStrategy.OnPush })
export class SignalComponent {
  count = signal(0);
  doubled = computed(() => this.count() * 2);
  increment() { this.count.update(n => n + 1); } // only doubled() re-runs
}$escape$,
  $escape$typescript$escape$,
